#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

// Structure to represent a tree node
typedef struct Node {
    int left;
    int right;
} Node;

// Function to calculate the number of ways to assign labels to a subtree
long long calculateWays(Node* nodes, int n, int node) {
    if (node == 0) return 1;
    long long ways = 0;
    for (int i = 1; i <= n; i++) {
        long long leftWays = 1;
        long long rightWays = 1;
        if (nodes[node].left != 0) {
            leftWays = calculateWays(nodes, i - 1, nodes[node].left);
        }
        if (nodes[node].right != 0) {
            rightWays = calculateWays(nodes, n - i, nodes[node].right);
        }
        ways = (ways + leftWays * rightWays) % MOD;
    }
    return ways;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        Node* nodes = (Node*) malloc(n * sizeof(Node));
        for (int i = 1; i <= n; i++) {
            int left, right;
            scanf("%d %d", &left, &right);
            nodes[i].left = left;
            nodes[i].right = right;
        }
        long long ways = calculateWays(nodes, n, 1);
        printf("%lld\n", ways);
        free(nodes);
    }
    return 0;
}

